module top_module(MO, A, B, desel, EN);input [3:0] A, B;
   input [1:0] desel;
   input EN;
   output reg [3:0] MO;

   always @ (EN or desel or A or B) begin
      if (EN) begin
         case (desel)
            2'b00: MO <= A;
            2'b01: MO <= B;
            2'b10: MO <= 4'b0000;
            2'b11: MO <= 4'b0000;
         endcase
      end else begin
         MO <= 4'b0000;
      end
   end
endmodule
